## 2.  `pcapng_stubs.c` – C / C++ glue

> **Important** – the file must be compiled as C++ (e.g. `g++`) because it
> includes the libpcapng C++ header.  The `extern "C"` block makes the entry
> points visible to the OCaml runtime.

```c
/* pcapng_stubs.c -----------------------------------------------------------
 *
 *  OCaml bindings for libpcapng (C++ iterator over frames).
 *
 *  Build with:
 *      ocamlc -c -ccopt -std=c++17 pcapng_stubs.c
 *      ocamlc -a -o libpcapng.cmxa pcapng_stubs.o -cclib -lstdc++
 *
 *  Or with ocamlopt:
 *      ocamlopt -c -ccopt -std=c++17 pcapng_stubs.c
 *      ocamlopt -a -o libpcapng.cmxa pcapng_stubs.o -cclib -lstdc++
 *
 *  The C++ source file that ships with libpcapng is expected to provide:
 *
 *      #include <pcapng.h>
 *
 *  The iterator API (this is a *very* small subset that we need):
 *
 *      namespace pcapng {
 *          class File;
 *          class FrameIterator {
 *          public:
 *              FrameIterator(const File&);
 *              bool   operator!=(const FrameIterator&) const;
 *              void   operator++();                // advance
 *              int64_t timestamp() const;          // ns since epoch
 *              const uint8_t* data() const;        // pointer to raw bytes
 *              size_t        length() const;        // number of bytes
 *          };
 *      }
 *
 *  The concrete API may differ; adapt the names below accordingly.
 *
 * -------------------------------------------------------------------------- */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <exception>
#include <string>
#include <cstring>

/* ------------------------------------------------------------------ */
/* Include the libpcapng C++ header.  Adjust the include path as needed */
extern "C" {
    /* The real header is C++, but we need the symbols in a C++ compilation unit */
}
#include "pcapng.h"          /* <-- replace with the actual path */

/* ------------------------------------------------------------------ */
/*  Wrapper that lives inside the OCaml custom block.
 *
 *  We keep two iterators: the current position and the sentinel (end).
 *
 *  The iterator objects are cheap (they just hold a pointer into the file
 *  buffer).  The File object itself owns the underlying memory.
 */
struct pcapng_iter {
    pcapng::File*         file;   /* owned by the wrapper */
    pcapng::FrameIterator cur;    /* current position */
    pcapng::FrameIterator end;    /* past‑the‑end sentinel */
};

/* ------------------------------------------------------------------ */
/*  Custom operations for the opaque OCaml value. */
static void pcapng_iter_finalize(value v) {
    struct pcapng_iter *it = *(struct pcapng_iter **)Data_custom_val(v);
    if (it) {
        delete it->file;          /* release the underlying File */
        delete it;                /* release the wrapper itself */
    }
}
static int pcapng_iter_compare(value v1, value v2) {
    struct pcapng_iter *a = *(struct pcapng_iter **)Data_custom_val(v1);
    struct pcapng_iter *b = *(struct pcapng_iter **)Data_custom_val(v2);
    if (a == b) return 0;
    return a < b ? -1 : 1;
}
static struct custom_operations pcapng_iter_ops = {
    "pcapng.iter",
    pcapng_iter_finalize,
    pcapng_iter_compare,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------ */
/*  Helper to allocate a custom block holding a pointer to struct pcapng_iter */
static value alloc_pcapng_iter(struct pcapng_iter *it) {
    value v = caml_alloc_custom(&pcapng_iter_ops, sizeof(struct pcapng_iter *), 0, 1);
    *(struct pcapng_iter **)Data_custom_val(v) = it;
    return v;
}

/* ------------------------------------------------------------------ */
/*  OCaml entry point:  val open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value v_fname) {
    CAMLparam1(v_fname);
    CAMLlocal1(v_res);

    const char *c_fname = String_val(v_fname);
    struct pcapng_iter *wrapper = nullptr;

    try {
        wrapper = new struct pcapng_iter;
        wrapper->file = new pcapng::File(c_fname);          // may throw
        wrapper->cur  = pcapng::FrameIterator(*wrapper->file);
        wrapper->end  = pcapng::FrameIterator();           // default‑constructed = end
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("pcapng: unknown exception while opening file");
    }

    v_res = alloc_pcapng_iter(wrapper);
    CAMLreturn(v_res);
}

/* ------------------------------------------------------------------ */
/*  OCaml entry point:  val close : t -> unit */
CAMLprim value caml_pcapng_close(value v_iter) {
    CAMLparam1(v_iter);
    struct pcapng_iter *it = *(struct pcapng_iter **)Data_custom_val(v_iter);
    /* The finalizer already deletes the wrapper; we just null it out so that
       double close is a no‑op. */
    if (it) {
        delete it->file;
        delete it;
        *(struct pcapng_iter **)Data_custom_val(v_iter) = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/*  The hot‑path: iterate over all frames and invoke the OCaml callback.
 *
 *  OCaml type of the callback (exposed in the .mli):
 *
 *        (int64 -> (int, int8_unsigned_elt, c_layout) Bigarray.Array1.t -> unit)
 *
 *  The callback is called *inside* the C++ loop, so the only marshalled
 *  value per iteration is the timestamp (int64).  The frame bytes are handed
 *  to OCaml as a zero‑copy external bigarray.
 *
 *  To stop early the user raises the exception `Pcapng.Stop_iteration`.
 *  The stub recognises it and breaks out of the loop silently.
 */
CAMLprim value caml_pcapng_iterate(value v_iter, value v_cb) {
    CAMLparam2(v_iter, v_cb);
    CAMLlocal3(v_ts, v_big, v_exc);

    struct pcapng_iter *wrap = *(struct pcapng_iter **)Data_custom_val(v_iter);
    if (!wrap) caml_failwith("pcapng: iterator already closed");

    try {
        for ( ; wrap->cur != wrap->end; ++wrap->cur ) {
            /* ---- 1. marshal timestamp ----------------------------------- */
            int64_t ts = wrap->cur.timestamp();   /* libpcapng timestamp */
            v_ts = caml_copy_int64(ts);           /* cheap allocation */

            /* ---- 2. create zero‑copy bigarray --------------------------- */
            const uint8_t *data_ptr = wrap->cur.data();
            size_t         data_len = wrap->cur.length();

            /* The data pointer is owned by the libpcapng File object.
               It stays valid until the next ++cur (or until the file is closed).
               Therefore we can safely expose it as an external bigarray. */
            v_big = caml_ba_alloc(CAML_BA_UINT8 | CAML_BA_EXTERNAL,
                                 1,                /* one dimension */
                                 (void *)data_ptr,
                                 data_len);
            /* No finalizer is attached – the memory is owned by the C++ side. */

            /* ---- 3. invoke the OCaml callback --------------------------- */
            v_exc = caml_callback2_exn(v_cb, v_ts, v_big);
            if (Is_exception_result(v_exc)) {
                /* If the exception is Stop_iteration we stop silently,
                   otherwise we re‑raise it to OCaml. */
                value exc = Extract_exception(v_exc);
                if (exc == caml_named_value("Pcapng.Stop_iteration")) {
                    /* normal early termination */
                    break;
                } else {
                    caml_raise(exc);
                }
            }
            /* loop continues */
        }
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("pcapng: unknown exception while iterating");
    }

    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/*  Register the Stop_iteration exception name so that we can compare it
 *  with the one raised from OCaml.
 *
 *  This code runs once when the shared library is loaded (via `caml_init`). */
CAMLprim value caml_pcapng_register_exns(value unit) {
    CAMLparam1(unit);
    /* The OCaml side will do:   exception Stop_iteration
     * The name we register must match exactly. */
    caml_register_named_value("Pcapng.Stop_iteration", caml_named_value("Pcapng.Stop_iteration"));
    CAMLreturn(Val_unit);
}
```

